CLBConfig.RunR:
vtks  = 50
solve = 5000
check_electric = 100
prev = 0
Solver$Actions$Init()
for (i in 1:solve) {
	Solver$Iter = i
	#cat(i)
	Solver$Actions$Iteration()  
	for (j in 1:500) # note that this should be increased to account for slow convergence of method 
	{
		Solver$Actions$Iter_Electric()
		if (j %% check_electric == 0) {
			diff = abs(prev - Solver$Quantities$ElectricField)
			criterion = sum(diff) / sum(abs(Solver$Quantities$ElectricField))
			if (criterion < 1e-7) {
				if (i %% vtks == 0) {cat("  iter:", i, "   Electric Iteration:", j, " Sum Difference:", criterion, "\n")}
				break
				}
			prev = Solver$Quantities$ElectricField
			#cat("  iter:", i, "   Electric Iteration:", j, " Sum Difference:", criterion, "\n")
			}
	}
	cat("  iter:", i, "   Electric Iteration:", j, " Sum Difference:", criterion, "\n")
	if (i %% vtks == 0)  {Solver() }
}
